// Função para obter uma saudação aleatória
function obterSaudacao() {
    const saudacoes = [
        "Fala, time de TI! 💻 Vamos codar com estilo hoje!",
        "E aí, equipe incrível! 🚀 Mais um dia para fazer acontecer!",
        "Oi, time! 🌟 Vocês são a força que move a tecnologia!",
        "Bora lá, pessoal! 🔧 Resolvendo problemas e criando soluções!",
        "Vamos com tudo, equipe! 💪 A TI não para, e vocês são demais!",
        "Saudações, mestres do código! 🧙‍♂️ Que a força esteja com vocês!",
        "Salve, equipe de TI! 🎉 Mais um dia para brilhar nos projetos!",
        "Fala, feras da tecnologia! 🌐 Juntos, dominamos o mundo digital!",
        "Oi, time espetacular! 🌟 O show da TI não pode parar!",
        "Bora lá, campeões da TI! 🏆 Hoje é mais um dia de conquistas!"
    ];
    // Retorna uma saudação aleatória da lista
    return saudacoes[Math.floor(Math.random() * saudacoes.length)];
}

// Função para obter a data atual formatada no padrão dd/mm/yyyy
function obterDataAtual() {
    const hoje = new Date();
    const dia = String(hoje.getDate()).padStart(2, '0');
    const mes = String(hoje.getMonth() + 1).padStart(2, '0');
    const ano = hoje.getFullYear();
    return `${dia}/${mes}/${ano}`;
}

// Inicializa a variável para armazenar todas as mensagens unificadas
let mensagemUnificada = "";

// Cria um objeto para armazenar os dados agrupados por ID e TÍTULO
let chamadosAgrupados = {};

// Itera sobre todos os dados do input
for (const item of $input.all()) {
    // Obtém as informações principais do chamado
    const id = item.json.ID || 'ID não informado';
    const titulo = item.json.TITULO || 'Título não informado';
    const nomeCompleto = item.json.NOME || 'Nome não informado';
    const usuarioAd = item.json.USUARIO || 'Usuário não informado';
    const email = item.json.Email || 'Email não informado';
    const senhaPadrao = item.json.SenhaPadrao || 'Senha não informada';
    const url = item.json.URL || 'URL não informada';

    // Se o chamado ainda não foi adicionado ao agrupamento, inicializa a estrutura
    if (!chamadosAgrupados[id]) {
        chamadosAgrupados[id] = {
            titulo: titulo,
            url: url,
            usuarios: []
        };
    }

    // Adiciona os dados do usuário à lista de usuários para este chamado
    chamadosAgrupados[id].usuarios.push({
        nomeCompleto: nomeCompleto,
        usuarioAd: usuarioAd,
        email: email,
        senhaPadrao: senhaPadrao
    });
}

// Obtém a saudação aleatória
const saudacao = obterSaudacao();

// Obtém a data atual
const dataAtual = obterDataAtual();

// Agora cria a mensagem unificada
for (const id in chamadosAgrupados) {
    const chamado = chamadosAgrupados[id];

    // Adiciona a saudação e a introdução
    mensagemUnificada += `${saudacao}\n\nAcessos criados!\n\n`;

    // Adiciona a informação de ID, TÍTULO e Data de Criação no início
    mensagemUnificada += `ID: ${id} - TITULO: ${chamado.titulo}\n`;
    mensagemUnificada += `Data de criação: ${dataAtual}\n\n`;

    // Adiciona as informações de cada usuário relacionado a este chamado
    for (const usuario of chamado.usuarios) {
        mensagemUnificada += `*${usuario.nomeCompleto}*\n`;
        mensagemUnificada += `- USUARIO AD: ${usuario.usuarioAd}\n`;
        mensagemUnificada += `- SENHA: ${usuario.senhaPadrao}\n`;
        mensagemUnificada += `- EMAIL: ${usuario.email}\n\n`;
    }

    // Adiciona o link para conferir o chamado
    mensagemUnificada += `Link do Chamado: ${chamado.url}\n\n`;
}

// Retorna a mensagem final no formato JSON contendo apenas uma string
return [
    {
        json: {
            textMessage: JSON.stringify(mensagemUnificada.trim())
        }
    }
];

