Write-Output "OK | $ouStatus | ADICIONADOS: $($gruposAdicionados -join ', ') | REMOVIDOS: $($gruposRemovidos -join ', ')"

=Import-Module ActiveDirectory

$usuario   = "{{ $json.USUARIO }}"
$ouDestino = "{{ $json.OU_DESTINO }}"

# Converte array JSON em string segura
$gruposRaw = "{{ $json.GRUPOS.join('||') }}"
$grupos    = $gruposRaw -split '\|\|'

# Grupos que NUNCA devem ser removidos
$gruposFixos = @("Domain Users")

$user = Get-ADUser -Filter "SamAccountName -eq '$usuario'" `
    -Properties DistinguishedName `
    -ErrorAction SilentlyContinue

if (-not $user) {
    Write-Output "USUARIO_NAO_ENCONTRADO"
    exit 0
}

# =========================
# MOVER PARA OU
# =========================
if ($user.DistinguishedName -notlike "*$ouDestino*") {
    Move-ADObject -Identity $user.DistinguishedName -TargetPath $ouDestino
    $ouStatus = "OU_MOVIDA"
}
else {
    $ouStatus = "OU_JA_CORRETA"
}

# =========================
# REMOVER GRUPOS ATUAIS
# =========================
$gruposRemovidos = @()

$gruposAtuais = Get-ADPrincipalGroupMembership $usuario |
    Where-Object { $_.Name -notin $gruposFixos } |
    Select-Object -ExpandProperty SamAccountName

foreach ($grupoAtual in $gruposAtuais) {
    if ($grupos -notcontains $grupoAtual) {
        try {
            Remove-ADGroupMember `
                -Identity $grupoAtual `
                -Members $usuario `
                -Confirm:$false
            $gruposRemovidos += $grupoAtual
        }
        catch {
            Write-Output "ERRO_REMOVER_GRUPO: $grupoAtual"
        }
    }
}

# =========================
# ADICIONAR GRUPOS NOVOS
# =========================
$gruposAdicionados = @()

foreach ($grupo in $grupos) {

    if ([string]::IsNullOrWhiteSpace($grupo)) { continue }

    try {
        if (-not (Get-ADGroupMember -Identity $grupo -Recursive |
            Where-Object { $_.SamAccountName -eq $usuario })) {

            Add-ADGroupMember -Identity $grupo -Members $usuario
            $gruposAdicionados += $grupo
        }
    }
    catch {
        Write-Output "ERRO_GRUPO: $grupo"
    }
}

